import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi, } from "vitest";
import { arm, disarm, writeAgentRunId } from "./arming.js";
import * as client from "./client.js";
import { captureFromHook } from "./index.js";
function writeTranscript(dir, lines) {
    const file = path.join(dir, "transcript.jsonl");
    const content = `${lines.map((l) => JSON.stringify(l)).join("\n")}\n`;
    fs.writeFileSync(file, content);
    return file;
}
function makeTurnRecord(role, text, ts) {
    return {
        type: "message",
        timestamp: ts ?? new Date().toISOString(),
        message: { role, content: text },
    };
}
describe("captureFromHook cleanup behavior", () => {
    let tempHome;
    let transcriptDir;
    let appendSpy;
    let stateSpy;
    const originalHome = process.env.HOME;
    const originalEnv = process.env.BITFAB_CAPTURE_SESSIONS;
    beforeEach(() => {
        tempHome = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-capture-"));
        transcriptDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-transcript-"));
        process.env.HOME = tempHome;
        process.env.BITFAB_CAPTURE_SESSIONS = "1";
        appendSpy = vi.spyOn(client, "appendChatSession");
        stateSpy = vi.spyOn(client, "getChatSessionState");
        stateSpy.mockResolvedValue(null);
    });
    afterEach(() => {
        process.env.HOME = originalHome;
        if (originalEnv === undefined) {
            delete process.env.BITFAB_CAPTURE_SESSIONS;
        }
        else {
            process.env.BITFAB_CAPTURE_SESSIONS = originalEnv;
        }
        fs.rmSync(tempHome, { recursive: true, force: true });
        fs.rmSync(transcriptDir, { recursive: true, force: true });
        vi.restoreAllMocks();
    });
    function makeInput(transcriptPath) {
        return {
            session_id: "test-session",
            transcript_path: transcriptPath,
            cwd: transcriptDir,
        };
    }
    it("cleans up armed state after successful SessionEnd flush", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        writeAgentRunId("test-session", "11111111-1111-4111-8111-111111111111");
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const result = await captureFromHook("SessionEnd", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(false);
        const agentRunIdFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.agent-run-id");
        expect(fs.existsSync(agentRunIdFile)).toBe(false);
    });
    it("flushes on Stop but keeps the session armed (Stop is not terminal)", async () => {
        // Stop fires at the end of every assistant turn. It must capture new turns
        // WITHOUT marking the session ended or disarming, or the session gets
        // summarized the moment the user stops interacting - even mid-conversation.
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        // Turns were flushed without an ended flag...
        expect(appendSpy).toHaveBeenCalledWith(expect.not.objectContaining({ ended: true }));
        // ...and the session stays armed so later turns keep getting captured.
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("uses the locally mapped agentRunId when the hook env no longer has it", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        const agentRunId = "11111111-1111-4111-8111-111111111111";
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        writeAgentRunId("test-session", agentRunId);
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledWith(expect.objectContaining({ agentRunId }));
    });
    it("prefers the locally mapped agentRunId over stale armed metadata", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        const currentAgentRunId = "22222222-2222-4222-8222-222222222222";
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
            agentRunId: "11111111-1111-4111-8111-111111111111",
        });
        writeAgentRunId("test-session", currentAgentRunId);
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledWith(expect.objectContaining({ agentRunId: currentAgentRunId }));
    });
    it("ignores SubagentStop entirely: no flush, no disarm of the live session", async () => {
        // SubagentStop carries the MAIN session_id but the subagent's transcript.
        // Treating it as terminal (the old behaviour) flushed the wrong transcript
        // and disarmed the still-running main session, dropping everything after the
        // first subagent. It must be a hard no-op instead.
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const result = await captureFromHook("SubagentStop", makeInput(transcriptPath));
        expect(result.status).toBe("skipped_subagent_stop");
        // Never touched the server, and the main session stays armed so its later
        // turns keep getting captured.
        expect(appendSpy).not.toHaveBeenCalled();
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("keeps capturing the main session AFTER a subagent finishes", async () => {
        // The regression: the old code disarmed on SubagentStop, so everything the
        // main agent did after the first subagent was dropped (skipped_not_armed).
        // Returning offset 0 each time keeps the mock simple: every flush re-reads
        // the whole transcript, so a grown file always yields turns.
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "u1"),
            makeTurnRecord("assistant", "a1"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 0,
            turnCount: 2,
        });
        // First flush captures the opening turns.
        const first = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(first.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledTimes(1);
        // A subagent finishes: no-op, no send, still armed.
        const sub = await captureFromHook("SubagentStop", makeInput(transcriptPath));
        expect(sub.status).toBe("skipped_subagent_stop");
        expect(appendSpy).toHaveBeenCalledTimes(1);
        // The main agent keeps working. THE PROOF: this is still captured, not
        // skipped_not_armed.
        fs.appendFileSync(transcriptPath, `${JSON.stringify(makeTurnRecord("user", "u2"))}\n${JSON.stringify(makeTurnRecord("assistant", "a2"))}\n`);
        const cont = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(cont.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledTimes(2);
    });
    it("preserves armed state when SessionEnd flush fails with network error", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: false,
            reason: "network",
            detail: "connection refused",
        });
        const result = await captureFromHook("SessionEnd", makeInput(transcriptPath));
        expect(result.status).toBe("error");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("preserves armed state when SessionEnd flush fails with auth error", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({ ok: false, reason: "auth" });
        const result = await captureFromHook("SessionEnd", makeInput(transcriptPath));
        expect(result.status).toBe("auth_missing");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("cleans up armed state when SessionEnd flush hits offset conflict", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: false,
            reason: "offset_conflict",
            lastTranscriptOffset: 50,
            turnCount: 1,
            nextSequence: 8,
        });
        const result = await captureFromHook("SessionEnd", makeInput(transcriptPath));
        expect(result.status).toBe("no_op");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        // offset_conflict returns no_op which is treated as safe to clean up,
        // because the server already has the data and resynced the offset
        expect(fs.existsSync(armedFile)).toBe(false);
    });
    it("preserves server nextSequence after offset conflict", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: false,
            reason: "offset_conflict",
            lastTranscriptOffset: 50,
            turnCount: 1,
            nextSequence: 8,
        });
        const result = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(result.status).toBe("no_op");
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        expect(JSON.parse(fs.readFileSync(offsetFile, "utf-8"))).toEqual({
            offset: 50,
            sequenceBase: 8,
        });
    });
    it("does not recreate offset state when a background flush finishes after the session is disarmed", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockImplementation(async () => {
            disarm("test-session");
            return {
                ok: true,
                id: "sess-1",
                lastTranscriptOffset: 100,
                turnCount: 1,
            };
        });
        const result = await captureFromHook("PreToolUse", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        expect(fs.existsSync(offsetFile)).toBe(false);
    });
    it("sends ended flag during compaction even with zero new turns", async () => {
        const transcriptPath = writeTranscript(transcriptDir, []);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        // Write an offset state that's larger than the current file size to
        // trigger the compaction path
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        fs.writeFileSync(offsetFile, JSON.stringify({ offset: 99999 }));
        stateSpy.mockResolvedValue({
            exists: true,
            lastTranscriptOffset: 50,
            turnCount: 2,
            status: "active",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 0,
            turnCount: 2,
        });
        const result = await captureFromHook("SessionEnd", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledWith(expect.objectContaining({
            ended: true,
            compacted: true,
        }));
    });
    it("returns no_op for compaction with zero turns on non-terminal hook", async () => {
        const transcriptPath = writeTranscript(transcriptDir, []);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        fs.writeFileSync(offsetFile, JSON.stringify({ offset: 99999 }));
        stateSpy.mockResolvedValue({
            exists: true,
            lastTranscriptOffset: 50,
            turnCount: 2,
            status: "active",
        });
        const result = await captureFromHook("PreCompact", makeInput(transcriptPath));
        expect(result.status).toBe("no_op");
        expect(appendSpy).not.toHaveBeenCalled();
    });
    it("uses remote nextSequence rather than turnCount after compaction", async () => {
        const transcriptPath = path.join(transcriptDir, "transcript.jsonl");
        fs.writeFileSync(transcriptPath, `${JSON.stringify(makeTurnRecord("user", "after compaction"))}\nnot-json\n${JSON.stringify(makeTurnRecord("assistant", "ack"))}\n`);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        fs.writeFileSync(offsetFile, JSON.stringify({ offset: 99999 }));
        stateSpy.mockResolvedValue({
            exists: true,
            lastTranscriptOffset: 50,
            turnCount: 2,
            nextSequence: 8,
            status: "active",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: fs.statSync(transcriptPath).size,
            turnCount: 4,
        });
        const result = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledWith(expect.objectContaining({
            compacted: true,
            turns: [
                expect.objectContaining({ sequence: 8 }),
                expect.objectContaining({ sequence: 10 }),
            ],
        }));
    });
    function armedMarker(sessionId) {
        return path.join(tempHome, ".config", "bitfab", "sessions", `${sessionId}.armed`);
    }
    it("never ends a sibling session, even one idle past the server timeout", async () => {
        // Regression: the sweep used to flush EVERY other armed session with
        // ended:true on any SessionStart, marking live parallel sessions ended and
        // firing their summary minutes in. Ending a session is the server-side idle
        // backstop's job, never a sibling's - so even a long-idle sibling whose
        // transcript still exists must be left armed and untouched.
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-sibling",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const siblingTranscript = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "idle but not abandoned"),
        ]);
        const threeHoursAgo = new Date(Date.now() - 3 * 60 * 60 * 1000);
        fs.utimesSync(siblingTranscript, threeHoursAgo, threeHoursAgo);
        arm("sibling-session", {
            transcriptPath: siblingTranscript,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const currentTranscript = path.join(transcriptDir, "current.jsonl");
        fs.writeFileSync(currentTranscript, `${JSON.stringify(makeTurnRecord("user", "new session"))}\n`);
        const result = await captureFromHook("SessionStart", {
            session_id: "current-session",
            transcript_path: currentTranscript,
            cwd: transcriptDir,
        });
        expect(result.status).toBe("skipped_not_armed");
        // Give any (wrongly) scheduled background flush a chance to run.
        await new Promise((resolve) => setTimeout(resolve, 25));
        expect(appendSpy).not.toHaveBeenCalled();
        expect(fs.existsSync(armedMarker("sibling-session"))).toBe(true);
    });
    it("prunes local marker for a sibling whose transcript is gone, without ending it", async () => {
        // Once Claude Code removes the transcript the session can never resume, so
        // its dead marker/offset files should be pruned - but still never flushed or
        // ended (the server owns the ended decision).
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-gone",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const goneTranscript = path.join(transcriptDir, "gone.jsonl");
        fs.writeFileSync(goneTranscript, `${JSON.stringify(makeTurnRecord("user", "will vanish"))}\n`);
        arm("gone-session", {
            transcriptPath: goneTranscript,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        // Claude Code removes the transcript.
        fs.rmSync(goneTranscript);
        const currentTranscript = path.join(transcriptDir, "current.jsonl");
        fs.writeFileSync(currentTranscript, `${JSON.stringify(makeTurnRecord("user", "new session"))}\n`);
        await captureFromHook("SessionStart", {
            session_id: "current-session",
            transcript_path: currentTranscript,
            cwd: transcriptDir,
        });
        await new Promise((resolve) => setTimeout(resolve, 25));
        // Marker pruned, but the session was never flushed or ended.
        expect(appendSpy).not.toHaveBeenCalled();
        expect(fs.existsSync(armedMarker("gone-session"))).toBe(false);
    });
});
